function solve(weight) {
    let n = weight.length;
    let maxWeight = 0;
    let result = 0;
    let i = 0;

    while (i < n) {
        let currentMax = 0;
        let lastElement = weight[i];
        let j = i;

        while (j < n) {
            currentMax = Math.max(currentMax, weight[j]);
            if (weight[j] < currentMax) {
                // Found a balanced shipment
                result++;
                // Move to the next element after the current shipment
                i = j + 1;
                break;
            }
            j++;
        }

        if (j === n) {
            // No more elements to process
            break;
        }
    }

    return result;
}

