#include <vector>
#include <algorithm>

long long solve(std::vector<long long> weight) {
    long long result = 0;
    int i = 0;
    int n = weight.size();

    while (i < n) {
        long long currentMax = 0;
        int j = i;
        while (j < n) {
            currentMax = std::max(currentMax, weight[j]);
